instruction:
Should I refactor this code that uses callbacks to use async/await? It's in a Node.js service that's working fine, but new team members complain it's hard to read.

```javascript
function processOrder(orderId, callback) {
  getOrder(orderId, (err, order) => {
    if (err) return callback(err);
    validateInventory(order.items, (err, available) => {
      if (err) return callback(err);
      if (!available) return callback(new Error('Out of stock'));
      chargePayment(order.total, (err, receipt) => {
        if (err) return callback(err);
        shipOrder(order, receipt, (err, tracking) => {
          if (err) return callback(err);
          callback(null, { orderId, tracking });
        });
      });
    });
  });
}
```
